mapper.select:
SELECT id, patient_id, patient_name, accession_number, gender, age, study_date, image_path, remark, created_at, updated_at
FROM ${tableName}

ORDER BY updated_at DESC, id DESC
LIMIT #{offset}, #{limit}

SELECT id, patient_id, patient_name, accession_number, gender, age, study_date, image_path, remark, created_at, updated_at
FROM ${tableName}
WHERE id = #{id}
LIMIT 1

SELECT id, patient_id, patient_name, accession_number, gender, age, study_date, image_path, remark, created_at, updated_at
FROM ${tableName}
WHERE accession_number = #{accessionNumber}
LIMIT 1
